#include<bits/stdc++.h>
using namespace std;
int a[505][505],n,m,DP[505][505],ans;
int main(void){
    cin>>n>>m;
    for(int i=1;i<=n;i++){
        for(int j=1;j<=m;j++){
            cin>>a[i][j];
            if(a[i][j])DP[i][j]=min(min(DP[i][j-1],DP[i-1][j]),DP[i-1][j-1])+1;
            ans=max(ans,DP[i][j]);
        }
    }
    cout<<ans;
}
